</head>
<body>

    <h1>Autonomous Bot Maze Challenge</h1>

    <div id="game-container">
        <!-- The Canvas for the maze rendering -->
        <canvas id="maze" width="400" height="400"></canvas>

        <!-- HUD and Controls -->
        <div id="hud">
            <h2>Status</h2>

            <div class="stat-item">
                <span class="stat-label">Completed Bots:</span>
                <div id="completed-count">0 / 24</div>
            </div>

            <div class="stat-item">
                <span class="stat-label">Time Elapsed:</span>
                <div id="timer">0.0s</div>
            </div>

            <button id="reset">Reset Game</button>
        </div>
    </div>

    <script>
        // =====================================================================
        // GLOBAL STATE AND CONSTANTS
        // =====================================================================

        const CANVAS_SIZE = 400;
        const CELL_PIXEL_SIZE = 20; // Using a grid of 20x20 cells (15x15 minimum requirement met)
        const GRID_COLS = Math.floor(CANVAS_SIZE / CELL_PIXEL_SIZE); // 20
        const GRID_ROWS = Math.floor(CANVAS_SIZE / CELL_PIXEL_SIZE); // 20

        // Maze dimensions (must be odd for perfect generation)
        const MAZE_GRID_W = 15;
        const MAZE_GRID_H = 15;

        let mazeGrid = []; // Stores wall data: true if wall exists, false otherwise.
        let bots = [];     // Array of bot objects
        let exitCell = { x: -1, y: -1 };
        let spawnCell = { x: Math.floor(MAZE_GRID_W / 2), y: Math.floor(MAZE_GRID_H / 2) };

        let startTime = null;
        let animationFrameId = null;
        let gameInterval = null;

        // Bot state management
        const BOT_STATE = {
            IDLE: 0,
            MOVING: 1,
            FINISHED: 2
        };


        // =====================================================================
        // CORE GAME LOGIC (MAZE GENERATION & PATHFINDING)
        // =====================================================================

        /**
         * Initializes the maze structure using Recursive Backtracker algorithm.
         */
        function generateMaze() {
            mazeGrid = Array(MAZE_GRID_H).fill(0).map(() => 
                Array(MAZE_GRID_W).fill(false) // false means no wall (path)
            );

            // Start at a random cell (must be odd coordinates for generation simplicity)
            let startX = 1;
            let startY = 1;

            const stack = [{ x: startX, y: startY }];
            mazeGrid[startY][startX] = false; // Mark starting cell as open

            while (stack.length > 0) {
                let current = stack[stack.length - 1];
                let neighbors = [];

                // Check unvisited neighbors (2 steps away, ensuring we jump over a wall)
                const potentialNeighbors = [
                    { dx: 0, dy: -2, nx: current.x, ny: current.y - 2 }, // North
                    { dx: 0, dy: 2, nx: current.x, ny: current.y + 2 },  // South
                    { dx: -2, dy: 0, nx: current.x - 2, ny: current.y }, // West
                    { dx: 2, dy: 0, nx: current.x + 2, ny: current.y }  // East
                ];

                for (const p of potentialNeighbors) {
                    let nx = p.nx;
                    let ny = p.ny;

                    if (nx >= 1 && nx < MAZE_GRID_W - 1 && ny >= 1 && ny < MAZE_GRID_H - 1 && !mazeGrid[ny][nx]) {
                        neighbors.push({ n: p, x: nx, y: ny });
                    }
                }

                if (neighbors.length > 0) {
                    // Pick a random unvisited neighbor
                    const next = neighbors[Math.floor(Math.random() * neighbors.length)];

                    // Mark the cell and the wall in between as open
                    mazeGrid[next.y][next.x] = false;
                    let wallY = Math.min(current.y, next.y) + (Math.max(current.y, next.y) - Math.min(current.y, next.y)) / 2;
                    let wallX = Math.min(current.x, next.x) + (Math.max(current.x, next.x) - Math.min(current.x, next.x)) / 2;

                    // The actual coordinates of the wall to knock down
                    if (next.y < current.y) { // Moving North
                        mazeGrid[current.y - 1][current.x] = false;
                    } else if (next.y > current.y) { // Moving South
                        mazeGrid[current.y + 1][current.x] = false;
                    } else if (next.x < current.x) { // Moving West
                        mazeGrid[current.y][current.x - 1] = false;
                    } else if (next.x > current.x) { // Moving East
                        mazeGrid[current.y][current.x + 1] = false;
                    }

                    stack.push(next);
                } else {
                    // Backtrack
                    stack.pop();
                }
            }
        }


        /**
         * Finds the path from start to end using Breadth-First Search (BFS).
         * Returns an array of coordinates [{x: ..., y: ...}, ...] or null if no path exists.
         */
        function findPath(start, end) {
            const queue = [[start.x, start.y]]; // Queue stores paths (array of coords)
            const visited = new Set();
            visited.add(`${start.x},${start.y}`);

            while (queue.length > 0) {
                const path = queue.shift();
                const current = path[path.length - 1];

                if (current.x === end.x && current.y === end.y) {
                    return path; // Found the path!
                }

                // Possible moves: Up, Down, Left, Right
                const neighbors = [
                    { x: current.x + 1, y: current.y },
                    { x: current.x - 1, y: current.y },
                    { x: current.x, y: current.y + 1 },
                    { x: current.x, y: current.y - 1 }
                ];

                for (const neighbor of neighbors) {
                    const key = `${neighbor.x},${neighbor.y}`;

                    // Check bounds, check if it's a path cell (not a wall), and check visited status
                    if (neighbor.x >= 0 && neighbor.x < MAZE_GRID_W && 
                        neighbor.y >= 0 && neighbor.y < MAZE_GRID_H &&
                        !mazeGrid[neighbor.y][neighbor.x] && // Must be a path cell
                        !visited.has(key)) {

                        visited.add(key);
                        const newPath = [...path, neighbor];
                        queue.push(newPath);
                    }
                }
            }
            return null; // No path found
        }


        /**
         * Initializes all bots and their paths.
         */
        function initializeBots() {
            bots = [];
            const numBots = 24;

            // 1. Find a guaranteed exit cell (e.g., corner opposite spawn)
            exitCell = { x: MAZE_GRID_W - 2, y: MAZE_GRID_H - 2 };
            if (!mazeGrid[exitCell.y][exitCell.x]) {
                // If the chosen exit is blocked by a wall (unlikely but possible), find another open cell.
                let found = false;
                for(let y=1; y < MAZE_GRID_H - 1; y++) {
                    for(let x=1; x < MAZE_GRID_W - 1; x++) {
                        if (mazeGrid[y][x] && (x !== spawnCell.x || y !== spawnCell.y)) {
                            exitCell = { x: x, y: y };
                            found = true;
                            break;
                        }
                    }
                    if(found) break;
                }
            }

            // 2. Calculate paths for all bots
            const pathLength = findPath(spawnCell, exitCell);

            if (!pathLength || pathLength.length < 2) {
                 console.error("Failed to generate a solvable maze or path.");
                 return false;
            }

            // The path array includes the start and end points. We need N-1 steps for N cells.
            const targetPath = pathLength; 

            for (let i = 0; i < numBots; i++) {
                bots.push({
                    id: i,
                    x: spawnCell.x * CELL_PIXEL_SIZE + CELL_PIXEL_SIZE / 2,
                    y: spawnCell.y * CELL_PIXEL_SIZE + CELL_PIXEL_SIZE / 2,
                    targetPath: targetPath, // The full path array
                    pathIndex: 0,           // Index of the next cell to move to (starts at 1)
                    isFinished: false,
                    element: null // Canvas element reference for drawing
                });
            }

            return true;
        }


        // =====================================================================
        // RENDERING AND ANIMATION LOOP
        // =====================================================================

        const canvas = document.getElementById('maze');
        const ctx = canvas.getContext('2d');

        /**
         * Draws the entire state: walls, bots, spawn, exit.
         */
        function draw() {
            // 1. Clear Canvas
            ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

            // 2. Draw Walls (Background)
            for (let y = 0; y < MAZE_GRID_H; y++) {
                for (let x = 0; x < MAZE_GRID_W; x++) {
                    const pixelX = x * CELL_PIXEL_SIZE;
                    const pixelY = y * CELL_PIXEL_SIZE;

                    ctx.fillStyle = mazeGrid[y][x] ? '#34495e' : '#2c3e50'; // Wall color vs Path color
                    ctx.fillRect(pixelX, pixelY, CELL_PIXEL_SIZE, CELL_PIXEL_SIZE);
                }
            }

            // 3. Draw Start/End Points (Overlaid)
            const drawPoint = (x, y, color, label) => {
                ctx.fillStyle = color;
                ctx.fillRect(x * CELL_PIXEL_SIZE + 5, y * CELL_PIXEL_SIZE + 5, CELL_PIXEL_SIZE - 10, CELL_PIXEL_SIZE - 10);
                ctx.font = '12px Arial';
                ctx.fillStyle = '#ecf0f1';
                ctx.textAlign = 'center';
                ctx.fillText(label, x * CELL_PIXEL_SIZE + CELL_PIXEL_SIZE / 2, y * CELL_PIXEL_SIZE + CELL_PIXEL_SIZE / 2 + 4);
            };

            // Draw Spawn (Top Left)
            drawPoint(spawnCell.x, spawnCell.y, '#f39c12', 'S');
            // Draw Exit (Bottom Right)
            drawPoint(exitCell.x, exitCell.y, '#2ecc71', 'E');


            // 4. Draw Bots
            bots.forEach((bot, index) => {
                const x = bot.x;
                const y = bot.y;

                ctx.beginPath();
                ctx.arc(x, y, CELL_PIXEL_SIZE * 0.35, 0, Math.PI * 2); // Bot size
                ctx.fillStyle = bot.isFinished ? '#95a5a6' : (index % 2 === 0 ? '#e74c3c' : '#3498db');
                ctx.fill();
                ctx.strokeStyle = '#1e272e';
                ctx.lineWidth = 2;
                ctx.stroke();
            });
        }

        /**
         * Updates the HUD elements (Timer and Completion Count).
         */
        function updateHUD() {
            const completedCount = bots.filter(b => b.isFinished).length;
            document.getElementById('completed-count').textContent = `${completedCount} / 24`;

            if (startTime) {
                const elapsedMs = Date.now() - startTime;
                const seconds = (elapsedMs / 1000).toFixed(1);
                document.getElementById('timer').textContent = `${seconds}s`;
            }
        }


        /**
         * The main animation loop using requestAnimationFrame.
         */
        function animateGame() {
            if (!window.game || !window.game.tick) return;

            // 1. Advance the simulation by one step (synchronous call to API)
            window.game.tick(0); // Passing 0 steps for animation tick

            // 2. Redraw everything based on new bot positions
            draw();
            updateHUD();

            if (!bots.some(b => b.isFinished)) {
                animationFrameId = requestAnimationFrame(animateGame);
            } else if (window.game.completed() < 24) {
                 // Keep animating until all bots are finished, even if the pathfinding is done
                 animationFrameId = requestAnimationFrame(animateGame);
            } else {
                console.log("All bots completed!");
                cancelAnimationFrame(animationFrameId);
                animationFrameId = null;
            }
        }


        // =====================================================================
        // API IMPLEMENTATION (window.game)
        // =====================================================================

        /**
         * Advances the simulation synchronously by N steps.
         * This function MUST be deterministic and fast for testing purposes.
         * @param {number} n - Number of steps to advance.
         */
        function gameTick(n) {
            let stepsTaken = 0;

            for (let i = 0; i < n && stepsTaken < n * 2; i++) { // Limit loop iterations for safety
                let movedAnyBot = false;
                bots.forEach(bot => {
                    if (!bot.isFinished) {
                        const nextStep = bot.targetPath[bot.pathIndex + 1];

                        // Check if the path is valid and we haven't reached the end yet
                        if (nextStep && !bot.isFinished) {
                            // Move to the next cell in the pre-calculated path
                            bot.x = nextStep.x * CELL_PIXEL_SIZE + CELL_PIXEL_SIZE / 2;
                            bot.y = nextStep.y * CELL_PIXEL_SIZE + CELL_PIXEL_SIZE / 2;
                            bot.pathIndex++;
                            movedAnyBot = true;

                            // Check for completion (The target cell is the exit)
                            if (nextStep.x === exitCell.x && nextStep.y === exitCell.y) {
                                bot.isFinished = true;
                            }
                        } else if (!nextStep) {
                             // Should not happen if pathfinding was correct, but handles edge case
                             bot.isFinished = true; 
                        }
                    }
                });

                if (movedAnyBot) {
                    stepsTaken++;
                } else {
                    break; // No bots moved, stop advancing time
                }
            }
        }


        /**
         * Resets the entire game state.
         */
        function resetGame() {
            // 1. Reset State Variables
            startTime = null;
            cancelAnimationFrame(animationFrameId);
            animationFrameId = null;

            // 2. Re-initialize Bots and Paths (This is crucial for determinism)
            if (!generateMaze()) {
                alert("Error: Could not generate a solvable maze.");
                return;
            }
            initializeBots();

            // 3. Reset Bot Positions/States
            bots.forEach(bot => {
                bot.x = spawnCell.x * CELL_PIXEL_SIZE + CELL_PIXEL_SIZE / 2;
                bot.y = spawnCell.y * CELL_PIXEL_SIZE + CELL_PIXEL_SIZE / 2;
                bot.pathIndex = 0;
                bot.isFinished = false;
            });

            // 4. Update UI and Start Loop
            updateHUD();
            draw(); // Initial draw
            animateGame();
        }


        // Expose the API globally
        window.game = {
            get bots() { return bots; },
            get completed() { return bots.filter(b => b.isFinished).length; },
            get elapsedMs() { 
                return startTime ? (Date.now() - startTime) : 0; 
            },
            tick: gameTick, // Synchronous advancement
            reset: resetGame
        };


        // =====================================================================
        // INITIALIZATION AND EVENT LISTENERS
        // =====================================================================

        document.getElementById('reset').addEventListener('click', () => {
            window.game.reset();
        });

        // Start the game when the script loads
        window.onload = () => {
            console.log("Game Initializing...");
            window.game.reset(); // This handles initial setup and starts the animation loop
        };

    </script>
</body>
</html>
